INSERT INTO TB_FILE_DTL (
	file_seq,
	file_nm,
	file_path,
	file_type,
	del_yn,
	sort_seq,
	rgst_user_seq,
	rgst_date_time,
	upt_user_seq,
	upt_date_time
) VALUES(
	#{fileSeq}
	,#{fileNm}
	,#{filePath}
	,#{fileType}
	,'N'
	,#{sortSeq}
	,#{rgstUserSeq}
	,NOW()
	,#{uptUserSeq}
	,NOW()
)

